# Explorer packet solve S42-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'json_schema', 'valid_fixture', 'business_rule', 'extra_policy', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (record["extra_policy"] == "allow" and not record["business_rule"])) else 'REJECT_SCHEMA'

valid = {'case_id': 'CASO-CUS-042-1A', 'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True}
invalid = {'case_id': 'CASO-CUS-042-1A', 'extra_policy': 'forbid', 'json_schema': True, 'valid_fixture': True, 'business_rule': True}
incomplete = {**valid}
incomplete.pop('business_rule', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

